(window.webpackJsonp=window.webpackJsonp||[]).push([[16],{281:function(t,_,s){"use strict";s.r(_);var a=s(13),p=Object(a.a)({},(function(){var t=this,_=t._self._c;return _("ContentSlotsDistributor",{attrs:{"slot-key":t.$parent.slotKey}},[_("h1",{attrs:{id:"从单片机到嵌入式开发-1-io口使用介绍"}},[_("a",{staticClass:"header-anchor",attrs:{href:"#从单片机到嵌入式开发-1-io口使用介绍"}},[t._v("#")]),t._v(" 从单片机到嵌入式开发——(1) IO口使用介绍")]),t._v(" "),_("p",[t._v("date: 2020-11-28")]),t._v(" "),_("p",[t._v("author: 西风镭")]),t._v(" "),_("p",[t._v("location: 宣城，合肥工业大学宣城校区")]),t._v(" "),_("p",[t._v("单片机对一切外部设备的交互动作，归根结底都是通过IO口的高低电平变换来实现的。通过控制高低电平的输出，单片机可以令外部设备开启或关闭，可以通过输出一定形态的波形驱动外部设备以特定的方式工作，可以通过输出比特流来进行数据的传输。通过读取高低电平的输入，单片机可以解码指定的信息，可以获得外部设备的状态，可以检测传感器的返回值……综上所述，关于单片机软件开发的一切，归根结底都是对IO端口的控制本身。")]),t._v(" "),_("p",[_("img",{attrs:{src:"https://img-blog.csdnimg.cn/20201128101123608.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzQyMTIxMjY1,size_16,color_FFFFFF,t_70#pic_center",alt:"51单片机基本封装图"}})]),t._v(" "),_("p",[t._v("如图所示是一款采用DIP40封装标准的51单片机。标准的单片机共有40个引脚(图中略去20号VCC和40号GND)。其中，XTAL为时钟晶振连接口，其决定了单片机的运算速度。RST为复位口，可以使单片机复位。PSEN等三个为系统扩展ROM/RAM所需要使用的引脚，此处不提。")]),t._v(" "),_("p",[t._v("其余P0-3则是通用的8位IO引脚，可以控制或读取该输入输出的电平高低，从而对单片机的外部设备进行操作。LED灯由高点平向低电平导通时方可点亮，故仅在一端电源一端接低电平端口或一端接高电平端口一端接地时点亮。")]),t._v(" "),_("p",[t._v("P1-3有内部上拉电阻，可直接用于输入/输出。P0无内部上拉电阻，需要连接外部上拉电阻方可实现输出，但在实际使用中，各家单片机最小系统厂商都会连接好上拉电阻，故使用时无影响。")]),t._v(" "),_("p",[_("img",{attrs:{src:"https://img-blog.csdnimg.cn/20201128101551467.png?x-oss-process=image/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L3FxXzQyMTIxMjY1,size_16,color_FFFFFF,t_70#pic_center",alt:"51单片机最小系统图"}})]),t._v(" "),_("p",[t._v("如图为单片机的最小系统。XTAL1和XTAL2之间连接晶振以及晶振电路，从而产生一个震荡脉冲，使单片机内部可以按时工作。晶振的脉冲周期为单片机的时钟周期，每个基本指令需要经过若干的时钟周期完成，最基本的指令一般需要6个时钟周期。若干条指令组成了我们的程序，因此晶振速度的快慢决定了我们程序运行的快慢。51单片机使用的晶振通常为11.0592MHz，实际中由于存在误差一般在12MHz上下。这个数字在进行与时间相关的运算中会频繁使用，所以需要留意。")]),t._v(" "),_("p",[t._v("RST引脚为复位引脚，该引脚通高电平一段时间自动复位。此处使用的是常见的按键复位电路，按下按键后RST引脚通高电平，程序回到初始状态。")]),t._v(" "),_("p",[t._v("单片机各端口在默认上电初始状态均通高电平（P0引脚连接上拉电阻后通高电平）。")]),t._v(" "),_("p",[t._v("51单片机程序烧录普遍需要冷启动，即开始烧录模式后需要关闭电源后重新开机（或硬件复位）方能进行下载，因为下载程序需要进入引导区。但是STC本身支持热启动下载（即不关机重启即可下载），普中自动下载工具便使用了这个方法，有兴趣的朋友可以自行搜索。")])])}),[],!1,null,null,null);_.default=p.exports}}]);